// lib/common/createNativeReadable.ts
import { Readable } from "stream";
import { Constants, Utils } from "youtubei.js";
var TEN_MB = 1048576 * 10;
function createNativeReadable(url, size, innertube, videoInfo) {
  let start = 0;
  let end = Math.min(size, TEN_MB);
  let isEnded = false;
  let abortController;
  return new Readable({
    async read() {
      if (isEnded) return;
      if (end >= size) {
        isEnded = true;
        end = size;
      }
      abortController = new AbortController();
      const fUrl = `${url}&cpn=${videoInfo.cpn}&range=${start}-${end || ""}`;
      const getReq = await innertube.session.http.fetch_function(fUrl, {
        headers: Constants.STREAM_HEADERS,
        signal: abortController.signal
      });
      if (!getReq.body)
        throw new Error(`Download of video failed at ${start / size * 100}%`);
      for await (const chunk of Utils.streamToIterable(getReq.body)) {
        this.push(Buffer.from(chunk));
      }
      if (isEnded) {
        this.push(null);
      }
      start = end + 1;
      end += TEN_MB;
    },
    destroy(err) {
      if (abortController) abortController.abort(err);
    }
  });
}

// lib/common/generateYTStream.ts
var DEFAULT_DOWNLOAD_OPTIONS = {
  quality: "best",
  format: "mp4",
  type: "audio"
};
async function streamFromYT(query, innerTube, options = {
  overrideDownloadOptions: DEFAULT_DOWNLOAD_OPTIONS
}) {
  const context = YoutubeiExtractor.getStreamingContext();
  let id = new URL(query.url).searchParams.get("v");
  if (!id) id = query.url.split("/").at(-1)?.split("?").at(0);
  const videoInfo = await innerTube.getBasicInfo(id, {
    client: context.useClient
  });
  if (videoInfo.basic_info.is_live)
    return videoInfo.streaming_data?.hls_manifest_url;
  let format = videoInfo.chooseFormat(
    options.overrideDownloadOptions || DEFAULT_DOWNLOAD_OPTIONS
  );
  if (["IOS", "ANDROID", "TV_EMBEDDED"].includes(
    context.useClient
  )) {
    if (!format.url || !format.content_length)
      throw new Error("Not matching URL for this format found");
    return createNativeReadable(
      format.url,
      format.content_length,
      innerTube,
      videoInfo
    );
  } else {
    format.url = await format.decipher(innerTube.session.player);
    if (!format.content_length)
      throw new Error("Not matching URL for this format found");
    return createNativeReadable(
      format.url,
      format.content_length,
      innerTube,
      videoInfo
    );
  }
}

// lib/Extractor/Youtube.ts
import { AsyncLocalStorage } from "node:async_hooks";

// lib/utils/index.ts
import { Platform } from "youtubei.js";
function defaultPeerUrlBuilder(url, id) {
  return `${url}/${id}`;
}
function defaultFetch(_player, input, init, proxy) {
  let requestInit = {
    ...init
  };
  if (proxy) {
    requestInit.dispatcher = proxy;
    return Platform.shim.fetch(input, requestInit);
  } else {
    return Platform.shim.fetch(input, requestInit);
  }
}

// lib/common/peerDownloader.ts
function peerDownloader(id, peer) {
  const peerUrl = typeof peer.parse === "function" ? peer.parse(peer.url, id) : defaultPeerUrlBuilder(peer.url, id);
  return peerUrl;
}

// lib/common/extractVideoID.ts
function extractVideoId(vid) {
  const YOUTUBE_REGEX = /^https:\/\/(www\.)?youtu(\.be\/.{11}(.+)?|be\.com\/watch\?v=.{11}(&.+)?)/;
  if (!YOUTUBE_REGEX.test(vid)) throw new Error("Invalid youtube url");
  let id = new URL(vid).searchParams.get("v");
  if (!id) id = vid.split("/").at(-1)?.split("?").at(0);
  return id;
}

// lib/token/tokenGenerator.ts
import { JSDOM } from "jsdom";
import { BG } from "bgutils-js";
async function generateToken(innertube) {
  const requestKey = "O43z0dpjhgX20SCx4KAo";
  const visitorData = innertube.session.context.client.visitorData;
  if (!visitorData) throw new Error("Could not get visitor data");
  const bgConfig = {
    fetch: (input, init) => fetch(input, init),
    globalObj: globalThis,
    identifier: visitorData,
    requestKey
  };
  const dom = new JSDOM();
  Object.assign(globalThis, {
    window: dom.window,
    document: dom.window.document
  });
  const bgChallenge = await BG.Challenge.create(bgConfig);
  if (!bgChallenge) throw new Error("Could not get challenge");
  const interpreterJavascript = bgChallenge.interpreterJavascript.privateDoNotAccessOrElseSafeScriptWrappedValue;
  if (interpreterJavascript) {
    new Function(interpreterJavascript)();
  } else throw new Error("Could not load VM");
  const poTokenResult = {
    ...await BG.PoToken.generate({
      program: bgChallenge.program,
      globalName: bgChallenge.globalName,
      bgConfig
    }),
    visitorData
  };
  try {
    globalThis.document.close();
  } catch {
  }
  delete globalThis.window;
  delete globalThis.document;
  return poTokenResult;
}

// lib/experimental/YoutubeDL.ts
import youtubeDl from "youtube-dl-exec";
import ytdlExec from "youtube-dl-exec";
import { mkdir, chmod } from "node:fs/promises";
import { pipeline } from "node:stream/promises";
import { createWriteStream } from "node:fs";
var { YOUTUBE_DL_PATH, YOUTUBE_DL_HOST, YOUTUBE_DL_DIR, YOUTUBE_DL_FILE } = ytdlExec.constants;
var UpdateError = class extends Error {
  type;
  constructor(type, message, errorOptions) {
    super(message, errorOptions);
    this.type = type;
  }
};
async function getDlBinary() {
  let binaryResponse = await fetch(YOUTUBE_DL_HOST);
  if (!binaryResponse.ok)
    throw new UpdateError("download", "Could not update youtube-dl");
  if (binaryResponse.headers.get("Content-Type") !== "application/octet-stream") {
    const { assets } = await binaryResponse.json();
    const { browser_download_url } = assets.find(
      ({ name }) => name === YOUTUBE_DL_FILE
    );
    binaryResponse = await fetch(browser_download_url);
    if (!binaryResponse.ok)
      throw new UpdateError("download", "Could not update youtube-dl");
  }
  if (!binaryResponse.body)
    throw new UpdateError("body_not_found", "Could not find body of the file");
  return binaryResponse.body;
}
async function updateDl() {
  const [binary] = await Promise.all([
    getDlBinary(),
    mkdir(YOUTUBE_DL_DIR, { recursive: true })
  ]);
  await pipeline(binary, createWriteStream(YOUTUBE_DL_PATH));
  await chmod(YOUTUBE_DL_PATH, 493);
}
async function generateStreamWithYoutubeDL(track, youtubei) {
  const videoId = extractVideoId(track.url);
  const videoUrl = "https://youtu.be/" + videoId;
  const videoFormat = track.live ? "best[height<=360]" : "bestaudio";
  const { context } = youtubei;
  const player = context.player;
  const process2 = youtubeDl.exec(videoUrl, {
    jsRuntimes: "node",
    format: videoFormat,
    output: "-",
    cookies: youtubei.options.cookie,
    noWarnings: true,
    noProgress: true
  });
  process2.catch((e) => {
    player.debug("YOUTUBEI: Ran into an error during stream extraction");
    if (youtubei.options.logLevel === "ALL") console.log(e);
  });
  const stream = process2.stdout;
  if (!stream) return void 0;
  const killProcess = () => !process2.killed && process2.kill();
  stream.on("close", killProcess);
  stream.on("error", killProcess);
  stream.on("end", killProcess);
  return stream;
}

